package programs;

public class LargestOfThreeNumbers {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=100,b=20,c=50;
		if(a>b&&a>c)
		{
			System.out.println("a is largest");
		}
		else if(b>a&&b>c)
		{
			System.out.println("b is largest");
		}
		else
		{
			System.out.println("c is largest");
		}

	}

}
